function Get-DirSize($p) {
    if (-not (Test-Path $p)) { return @{ Bytes = 0; Files = 0 } }
    $items = Get-ChildItem -LiteralPath $p -Recurse -File -Force -ErrorAction SilentlyContinue
    $sum = ($items | Measure-Object -Property Length -Sum).Sum
