}
function Format-Size($b) {
    if ($b -gt 1GB) { return "{0:N2} GB" -f ($b/1GB) }
    elseif ($b -gt 1MB) { return "{0:N1} MB" -f ($b/1MB) }
    elseif ($b -gt 1KB) { return "{0:N1} KB" -f ($b/1KB) }
