def demo1_run(layout_path_text: str):
    """
    Tab 1 入口：真实调用 cad_parser.astar_topology.run_pipeline，
    并渲染 2x2 四联可视化图（栅格 / 距离场 / A*访问热力 / 拓扑标签）。

    Args:
        layout_path_text: FloorplanQA JSON 文件的路径字符串。
    Returns:
        (json_text, image_path, status_md)
        - json_text: AreaGraph / Topology JSON 字符串，或错误 JSON
        - image_path: 4 联图 PNG 路径，失败时为 None
        - status_md: 状态条 Markdown
    """
    path_str = (layout_path_text or "").strip()
    if not path_str:
        return (
            json.dumps(
                {"error": "path_empty",
                 "hint": "请输入 FloorplanQA JSON 文件路径，或点击 [加载预设样本] 按钮。"},
                indent=2, ensure_ascii=False,
            ),
            None,
            "❌ 路径为空。",
        )

    layout_path = Path(path_str)
    if not layout_path.exists():
        return (
            json.dumps(
                {"error": "file_not_found", "path": path_str},
                indent=2, ensure_ascii=False,
            ),
            None,
            f"❌ 文件不存在：`{path_str}`",
        )

    try:
        from cad_parser.astar_topology import run_pipeline  # noqa: PLC0415
        from cad_parser.visualize import render_pipeline_quad  # noqa: PLC0415
    except ImportError as e:
        return (
            json.dumps(
                {"error": "import_cad_parser_failed", "message": str(e)},
                indent=2, ensure_ascii=False,
            ),
            None,
            f"❌ 导入失败：{e}",
        )

    try:
        result = run_pipeline(
            str(layout_path),
            resolution=0.05,
            robot_radius_m=0.25,
            include_grid=True,   # 可视化需要保留 grid/distance_field 等数组
        )
    except Exception:
        return (
            json.dumps(
                {"error": "pipeline_exception",
                 "traceback": traceback.format_exc().splitlines()[-12:]},
                indent=2, ensure_ascii=False,
            ),
            None,
            "❌ 流水线异常，详见输出。",
        )

    out_png = _OUT_DIR / f"demo1_{layout_path.stem}.png"
    try:
        render_pipeline_quad(result, str(out_png),
                             title_prefix=f"Demo 1 — {layout_path.name}")
        png_path: Optional[str] = str(out_png)
    except Exception:
        png_path = None

    topology = result.get("topology_json", {})
    output = {
        "_pipeline_ok": True,
        "_source_file": path_str,
        "_dataset_note": (
            "FloorplanQA (Bahmani et al. 2024, 公开数据集) — "
            "本流水线为确定性算法（栅格化 + EDT + A*），不涉及训练。"
        ),
        **topology,
    }
    n_nodes = len(topology.get("nodes", []))
    summary = topology.get("summary", {})
    status = (
        f"✅ 解析完成 · 节点数 = {n_nodes} · "
        f"可走比例 = {summary.get('path_fraction', 0):.1%} · "
        f"最大空间 = {summary.get('max_clearance_m', 0):.2f} m"
    )
    return (
        json.dumps(output, indent=2, ensure_ascii=False, default=str),
        png_path,
        status,
    )

