                   if min_d is not None else "ρ(t) — no Distance constraint"),
        )
        rho_png_str: Optional[str] = str(rho_png)
    except Exception:
        rho_png_str = None

    icon = "✅" if n_violations == 0 else "⚠️"
    status = (
        f"{icon} {n_violations} / {len(reports)} 条约束被违反 · "
        f"距离场: {bundle_status}"
    )
    return json_text, traj_png_str, rho_png_str, status

def demo2_infer_context(instruction: str):
    """Tab 2 辅助：从指令推断 nearest_objects；返回 (json_text, status_md)。"""
    if not instruction or not instruction.strip():
        return "", "❌ 请先在上面输入自然语言指令。"
    try:
        vlm = _get_vlm()
        ctx = vlm.infer_local_context(instruction)
    except VlmParserError as e:
        return "", f"❌ 推断失败：{e}"
    return (
        json.dumps(ctx, indent=2, ensure_ascii=False),
        f"✅ 已抽取 {len(ctx.get('nearest_objects', []))} 个实体；"
        f"如有不准可手动调整后再编译。",
    )


def demo2_summarize(roboir_json_text: str):
    """Tab 2 辅助：把 RoboIR 翻译回中文摘要；返回 (text, status_md)。"""
    if not roboir_json_text or not roboir_json_text.strip():
        return "", "❌ 请先编译生成 RoboIR。"
    try:
        roboir = json.loads(roboir_json_text)
    except json.JSONDecodeError:
        return "", "❌ RoboIR 不是合法 JSON。"
    if "error" in roboir:
        return "", "❌ 当前 RoboIR 是错误对象，无法摘要。"
    try:
        vlm = _get_vlm()
        text = vlm.summarize_roboir(roboir)
    except VlmParserError as e:
        return "", f"❌ 摘要失败：{e}"
